import "./App.css";
import React, { useRef } from "react";
function App() {
  const contentEl = useRef(null);

  const handleClick = () => {
    console.log("Button was clicked");
    contentEl.current.classList.toggle("content hidden");
  };

  return (
    <div>
      <button
        id="collapsible-button"
        type="button"
        className="collapsible"
        onClick={handleClick}
      >
        Open Collapsible
      </button>
      <div ref={contentEl} className="content hidden">
        <p>Lorem ipsum...</p>
      </div>
    </div>
  );
}

export default App;
